//! # Cache Manager
//!
//! Manages the generated code cache in target/rune-cache/.

use std::path::{Path, PathBuf};
use std::fs;

/// Cache manager for generated code.
#[derive(Debug)]
pub struct CacheManager {
    /// Root cache directory
    root: PathBuf,
}

impl CacheManager {
    /// Create a new cache manager.
    ///
    /// # Errors
    /// Returns an error if the cache directory cannot be created.
    pub fn new(workspace: &Path) -> std::io::Result<Self> {
        let root = workspace.join("target/rune-cache");
        fs::create_dir_all(&root)?;
        Ok(Self { root })
    }

    /// Get the generated code directory.
    #[must_use]
    pub fn generated_dir(&self) -> PathBuf {
        self.root.join("generated")
    }

    /// Get the path for a generated module.
    #[must_use]
    pub fn module_path(&self, module_name: &str) -> PathBuf {
        self.generated_dir().join(format!("{module_name}.rs"))
    }

    /// Get the path to the generated Cargo.toml.
    #[must_use]
    pub fn generated_cargo_toml(&self) -> PathBuf {
        self.root.join("Cargo.toml")
    }

    /// Check if a source file needs regeneration.
    #[must_use]
    pub fn needs_regeneration(&self, source: &Path) -> bool {
        let source_mtime = fs::metadata(source)
            .and_then(|m| m.modified())
            .ok();

        let cache_mtime = fs::metadata(self.generated_cargo_toml())
            .and_then(|m| m.modified())
            .ok();

        match (source_mtime, cache_mtime) {
            (Some(st), Some(ct)) => st > ct,
            _ => true,
        }
    }

    /// Clean the cache.
    ///
    /// # Errors
    /// Returns an error if the cache cannot be cleaned.
    pub fn clean(&self) -> std::io::Result<()> {
        if self.root.exists() {
            fs::remove_dir_all(&self.root)?;
            fs::create_dir_all(&self.root)?;
        }
        Ok(())
    }

    /// Get the hot reload directory.
    #[must_use]
    pub fn hot_dir(&self) -> PathBuf {
        self.root.parent()
            .unwrap_or(&self.root)
            .join("hot")
    }

    /// Get the current dylib symlink.
    #[must_use]
    pub fn current_dylib_link(&self) -> PathBuf {
        self.hot_dir().join(".current")
    }
}

// main.r.ts - Main entry point for the app logic

import { AppState, Task, Filter } from "./state.r.ts";

/**
 * Update application state.
 * Called by the host on each tick.
 */
export function update(state: AppState): void {
    // Filter tasks based on current filter
    const filtered = filterTasks(state.tasks, state.filter);

    // Clamp selected index
    if (state.selected >= filtered.length && filtered.length > 0) {
        state.selected = filtered.length - 1;
    }
}

/**
 * Filter tasks by completion status.
 */
export function filterTasks(tasks: Task[], filter: Filter): Task[] {
    switch (filter) {
        case Filter.Active:
            return tasks.filter(t => !t.done);
        case Filter.Completed:
            return tasks.filter(t => t.done);
        default:
            return tasks;
    }
}

/**
 * Get statistics about tasks.
 */
export function getStats(tasks: Task[]): { total: number; done: number; active: number } {
    const done = tasks.filter(t => t.done).length;
    return {
        total: tasks.length,
        done,
        active: tasks.length - done,
    };
}

/**
 * Find task by ID.
 */
export function findTask(tasks: Task[], id: number): Task | null {
    for (const task of tasks) {
        if (task.id === id) {
            return task;
        }
    }
    return null;
}

/**
 * Sort tasks by various criteria.
 */
export function sortTasks(tasks: Task[], by: "id" | "title" | "done"): Task[] {
    const sorted = [...tasks];
    switch (by) {
        case "id":
            return sorted.sort((a, b) => a.id - b.id);
        case "title":
            return sorted.sort((a, b) => a.title.localeCompare(b.title));
        case "done":
            return sorted.sort((a, b) => (a.done === b.done) ? 0 : a.done ? 1 : -1);
        default:
            return sorted;
    }
}

// state.r.ts - Application state types

/**
 * A task item.
 */
export type Task = {
    id: number;
    title: string;
    done: boolean;
};

/**
 * Filter mode for task list.
 */
export enum Filter {
    All = "all",
    Active = "active",
    Completed = "completed",
}

/**
 * Application state owned by host.
 */
export type AppState = {
    tasks: Task[];
    selected: number;
    filter: Filter;
    shouldExit: boolean;
};

/**
 * Message types for the app.
 */
export type Message =
    | { tag: "AddTask", title: string }
    | { tag: "ToggleTask", id: number }
    | { tag: "DeleteTask", id: number }
    | { tag: "SelectTask", index: number }
    | { tag: "SetFilter", filter: Filter }
    | { tag: "Quit" };

/**
 * Result type for operations.
 */
export type Result<T, E = string> =
    | { ok: true, value: T }
    | { ok: false, error: E };

/**
 * Create a new task.
 */
export function createTask(title: string): Task {
    return {
        id: Date.now(),
        title,
        done: false,
    };
}

/**
 * Toggle task completion.
 */
export function toggleTask(task: Task): Task {
    return { ...task, done: !task.done };
}

/**
 * Validate task title.
 */
export function validateTitle(title: string): Result<string> {
    const trimmed = title.trim();
    if (trimmed.length === 0) {
        return { ok: false, error: "Title cannot be empty" };
    }
    if (trimmed.length > 100) {
        return { ok: false, error: "Title too long (max 100 chars)" };
    }
    return { ok: true, value: trimmed };
}

